"""
COGNIVEX - Model Engine v2
Two-layer detection:
  Layer 1 — Hard rules: catch obvious deviations (fast/no typing, wild mouse speed)
  Layer 2 — Isolation Forest: catch subtle pattern shifts

idle_ratio dropped (zero variance in training data — useless to model).
Pre-trained on 15 real sessions from behavior_features_rows.csv.
"""

import joblib
import io
import base64
import numpy as np
from sklearn.ensemble import IsolationForest
from sklearn.preprocessing import StandardScaler
from typing import Dict, Optional, Tuple

FEATURE_ORDER = [
    'typing_speed',
    'backspace_ratio',
    'avg_keystroke_interval',
    'keystroke_variance',
    'avg_mouse_speed',
    'mouse_move_variance',
    'scroll_frequency',
    # idle_ratio excluded — all-zero variance in training data, useless feature
]

# ── Embedded pre-trained artifacts ─────────────────────────────────────────
_MODEL_B64 = """"""
_SCALER_B64 = """"""
_STATS_B64  = """gASVmgAAAAAAAAB9lCiMBW1lYW5zlF2UKEdAEGelf8h+0Ec/mci7xhRL5kc/0FEDtv0QGUc/1Je5ffPaEUdAafWGGGu/+0dAfPCnnZ4LGUc/9w9UnDmHDGWMBHN0ZHOUXZQoRz/XcpI0NlMgRz+LF8ZLIkgpRz+dqtgxUUMrRz/FNliFdyGLR0Bic1sqsSr1R0BrbvNZvnlIRz/mHGX/kkvXZXUu"""  # {means, stds} per feature


def _load_embedded():
    model  = joblib.load(io.BytesIO(base64.b64decode(_MODEL_B64.strip())))
    scaler = joblib.load(io.BytesIO(base64.b64decode(_SCALER_B64.strip())))
    stats  = joblib.load(io.BytesIO(base64.b64decode(_STATS_B64.strip())))
    return model, scaler, stats


class ModelEngine:

    SCORE_LOW    = -0.1
    SCORE_MEDIUM = -0.3
    ZSCORE_RULE  = 3.5     # flag if feature deviates > 2σ from personal baseline

    def __init__(self, supabase):
        self.supabase    = supabase
        self.model_cache = {}

    # ── helpers ────────────────────────────────────────────────────────────

    def _to_array(self, features: Dict[str, float]) -> np.ndarray:
        return np.array([features.get(f, 0.0) for f in FEATURE_ORDER]).reshape(1, -1)

    def _build_matrix(self, sessions: list) -> np.ndarray:
        return np.array([[s.get(f, 0.0) for f in FEATURE_ORDER] for s in sessions])

    def _serialize(self, obj) -> bytes:
        buf = io.BytesIO(); joblib.dump(obj, buf); return buf.getvalue()

    def _deserialize(self, data: bytes):
        return joblib.load(io.BytesIO(data))

    def _save_and_clear_cache(self, user_id, model, scaler, stats, version, total):
        self.supabase.save_model(user_id, self._serialize(model), version, total)
        self.supabase.save_scaler(user_id, self._serialize({'scaler': scaler, 'stats': stats}))
        self.model_cache.pop(user_id, None)

    # ── hard rules ─────────────────────────────────────────────────────────

    def _hard_rule_check(self, features: Dict[str, float],
                         means: list, stds: list) -> Tuple[Optional[str], Optional[str]]:
        """
        Returns (risk_level, reason) if a hard rule fires, else (None, None).
        Catches things Isolation Forest misses when training data is small.
        """
        ts = features.get('typing_speed', 0)
        ki = features.get('avg_keystroke_interval', 0)
        ms = features.get('avg_mouse_speed', 0)

        ts_mean, ts_std = means[0], stds[0]
        ki_mean, ki_std = means[2], stds[2]
        ms_mean, ms_std = means[4], stds[4]

        z = self.ZSCORE_RULE

        if ts == 0:
            return 'MEDIUM', 'no typing in snapshot'
        if ts > ts_mean + z * ts_std:
            return 'MEDIUM', f'typing speed {ts:.2f} > {ts_mean + z*ts_std:.2f} (personal max)'
        if ts < ts_mean - z * ts_std and ts > 0:
            return 'MEDIUM', f'typing speed {ts:.2f} < {ts_mean - z*ts_std:.2f} (personal min)'
        if ki > ki_mean + z * ki_std:
            return 'MEDIUM', f'keystroke interval {ki:.3f} too high (hesitant)'

        return None, None

    # ── public API ─────────────────────────────────────────────────────────

    def getModel(self, user_id: str) -> Optional[Dict]:
        meta   = self.supabase.get_model_metadata(user_id)
        db_ver = meta.get('model_version', 0) if meta else 0
        cached = self.model_cache.get(user_id)
        if cached and cached['model_version'] == max(db_ver, 1):
            return cached

        # Try DB model (user has retrained beyond embedded)
        if db_ver > 0:
            model_bytes  = self.supabase.get_model_data(user_id)
            scaler_bytes = self.supabase.get_scaler_data(user_id)
            if model_bytes and scaler_bytes:
                try:
                    scaler_bundle = self._deserialize(scaler_bytes)
                    result = {
                        'model':         self._deserialize(model_bytes),
                        'scaler':        scaler_bundle['scaler'],
                        'stats':         scaler_bundle['stats'],
                        'model_version': db_ver,
                    }
                    self.model_cache[user_id] = result
                    return result
                except Exception as e:
                    print(f"⚠️  DB model load failed, using embedded: {e}")

        # Embedded fallback
        print(f"   Using embedded pre-trained model")
        model, scaler, stats = _load_embedded()
        result = {'model': model, 'scaler': scaler, 'stats': stats, 'model_version': 1}
        self.model_cache[user_id] = result
        return result

    def predict(self, model, scaler, features: Dict[str, float],
                stats: dict = None) -> Tuple[float, str]:
        """Returns (score, source) where source is 'RULE' or 'MODEL'."""

        # Layer 1: hard rules
        if stats:
            risk, reason = self._hard_rule_check(features, stats['means'], stats['stds'])
            if risk:
                print(f"   ⚡ Hard rule fired: {reason}")
                return -0.15, 'RULE'

        # Layer 2: Isolation Forest
        normalized = scaler.transform(self._to_array(features))
        score = float(model.decision_function(normalized)[0])
        return score, 'MODEL'

    def scoreToRiskLevel(self, score: float) -> str:
        if score > self.SCORE_LOW:
            return 'LOW'
        elif score > self.SCORE_MEDIUM:
            return 'MEDIUM'
        return 'HIGH'

    def _train(self, sessions: list):
        matrix = self._build_matrix(sessions)
        means  = matrix.mean(axis=0).tolist()
        stds   = matrix.std(axis=0).tolist()
        stats  = {'means': means, 'stds': stds}
        scaler = StandardScaler()
        X_norm = scaler.fit_transform(matrix)
        model  = IsolationForest(contamination=0.1, n_estimators=200, random_state=42)
        model.fit(X_norm)
        print(f"   Trained on {len(sessions)} sessions | score range: "
              f"{model.decision_function(X_norm).min():.4f} – "
              f"{model.decision_function(X_norm).max():.4f}")
        return model, scaler, stats

    def trainModelV1(self, user_id: str) -> Dict:
        print(f"\n🤖 Training Model v1 — user {user_id}")
        sessions = self.supabase.get_latest_sessions(user_id, 15)
        if len(sessions) < 15:
            raise Exception(f"Not enough sessions: {len(sessions)} < 15")
        model, scaler, stats = self._train(sessions)
        self._save_and_clear_cache(user_id, model, scaler, stats, version=1, total=15)
        print(f"   ✅ Model v1 saved")
        return {'model_version': 1, 'total_sessions': 15}

    def retrainModel(self, user_id: str, total_sessions: int) -> Dict:
        print(f"\n🤖 Retraining — user {user_id}")
        sessions    = self.supabase.get_latest_sessions(user_id, 15)
        meta        = self.supabase.get_model_metadata(user_id)
        new_version = meta['model_version'] + 1
        model, scaler, stats = self._train(sessions)
        self._save_and_clear_cache(user_id, model, scaler, stats,
                                   version=new_version, total=total_sessions)
        print(f"   ✅ Model v{new_version} saved")
        return {'model_version': new_version, 'total_sessions': total_sessions}

    def getModelMetadata(self, user_id: str) -> Dict:
        return self.supabase.get_model_metadata(user_id)